class SocialLoginManager private constructor(
    private val context: Context,
    private val googleClient: GoogleSignInClient
) {
    companion object {
        fun create(context: Context): SocialLoginManager {
            val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
                .requestEmail()
                .requestProfile()
                .requestIdToken(SocialLoginConfig.GOOGLE_WEB_CLIENT_ID)
                .build()

            val client = GoogleSignIn.getClient(context.applicationContext, gso)
            return SocialLoginManager(context.applicationContext, client)
        }
    }

    fun signOutGoogle() {
        googleClient.signOut()
    }

    fun getGoogleSignInIntent(): Intent = googleClient.signInIntent

    @MainThread
    fun handleGoogleResult(task: Task<GoogleSignInAccount>): SocialLoginResult {
        return try {
            val account = task.getResult(ApiException::class.java)
            SocialLoginResult.Success(
                provider = Provider.GOOGLE,
                idToken = account.idToken,
                userId = account.id,
                email = account.email,
                displayName = account.displayName
            )
        } catch (e: ApiException) {
            SocialLoginResult.Error(Provider.GOOGLE, "Google sign-in failed: ${e.statusCode}", e)
        } catch (t: Throwable) {
            SocialLoginResult.Error(Provider.GOOGLE, "Google sign-in failed", t)
        }
    }
}

class FacebookOAuthPkce(
    private val context: Context
) {
    data class AuthRequest(
        val authUri: Uri,
        val codeVerifier: String,
        val state: String
    )

    fun buildAuthRequest(): AuthRequest {
        val state = Pkce.randomUrlSafe(16)
        val codeVerifier = Pkce.randomUrlSafe(64)
        val codeChallenge = Pkce.sha256Base64Url(codeVerifier)

        val uri = Uri.Builder()
            .scheme("https")
            .authority("www.facebook.com")
            .appendPath("v19.0")
            .appendPath("dialog")
            .appendPath("oauth")
            .appendQueryParameter("client_id", SocialLoginConfig.FACEBOOK_APP_ID)
            .appendQueryParameter("redirect_uri", SocialLoginConfig.FACEBOOK_REDIRECT_URI)
            .appendQueryParameter("response_type", "code")
            .appendQueryParameter("scope", SocialLoginConfig.FACEBOOK_SCOPES.joinToString(","))
            .appendQueryParameter("state", state)
            .appendQueryParameter("code_challenge", codeChallenge)
            .appendQueryParameter("code_challenge_method", "S256")
            .build()

        return AuthRequest(uri, codeVerifier, state)
    }

    fun parseRedirect(
        redirectUri: Uri,
        expectedState: String
    ): SocialLoginResult {
        val state = redirectUri.getQueryParameter("state")
        if (state == null || state != expectedState) {
            return SocialLoginResult.Error(Provider.FACEBOOK, "Invalid state")
        }

        val error = redirectUri.getQueryParameter("error")
        val errorReason = redirectUri.getQueryParameter("error_reason")
        val errorDescription = redirectUri.getQueryParameter("error_description")

        if (!error.isNullOrBlank()) {
            val msg = listOfNotNull(error, errorReason, errorDescription).joinToString(" | ")
            return SocialLoginResult.Error(Provider.FACEBOOK, "Facebook OAuth error: $msg")
        }

        val code = redirectUri.getQueryParameter("code")
        if (code.isNullOrBlank()) {
            return SocialLoginResult.Cancelled(Provider.FACEBOOK)
        }

        return SocialLoginResult.Success(
            provider = Provider.FACEBOOK,
            authorizationCode = code
        )
    }
}

object Pkce {
    private val secureRandom = java.security.SecureRandom()

    fun randomUrlSafe(lengthBytes: Int): String {
        val bytes = ByteArray(lengthBytes)
        secureRandom.nextBytes(bytes)
        return android.util.Base64.encodeToString(bytes, android.util.Base64.URL_SAFE or android.util.Base64.NO_WRAP or android.util.Base64.NO_PADDING)
    }

    fun sha256Base64Url(input: String): String {
        val md = java.security.MessageDigest.getInstance("SHA-256")
        val digest = md.digest(input.toByteArray(Charsets.US_ASCII))
        return android.util.Base64.encodeToString(digest, android.util.Base64.URL_SAFE or android.util.Base64.NO_WRAP or android.util.Base64.NO_PADDING)
    }
}

class SocialLoginUi(
    private val fragment: Fragment,
    private val onResult: (SocialLoginResult) -> Unit
) {
    private val manager = SocialLoginManager.create(fragment.requireContext())
    private val facebook = FacebookOAuthPkce(fragment.requireContext())

    private var pendingFacebookState: String? = null
    private var pendingFacebookVerifier: String? = null

    private val googleLauncher: ActivityResultLauncher<Intent> =
        fragment.registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            if (result.resultCode != Activity.RESULT_OK) {
                onResult(SocialLoginResult.Cancelled(Provider.GOOGLE))
                return@registerForActivityResult
            }
            val task = GoogleSignIn.getSignedInAccountFromIntent(result.data)
            onResult(manager.handleGoogleResult(task))
        }

    private val facebookLauncher: ActivityResultLauncher<Intent> =
        fragment.registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            val data = result.data
            val uri = data?.data
            val expectedState = pendingFacebookState
            pendingFacebookState = null

            if (result.resultCode != Activity.RESULT_OK || uri == null || expectedState == null) {
                onResult(SocialLoginResult.Cancelled(Provider.FACEBOOK))
                return@registerForActivityResult
            }

            onResult(facebook.parseRedirect(uri, expectedState))
        }

    fun startGoogle() {
        googleLauncher.launch(manager.getGoogleSignInIntent())
    }

    fun startFacebook() {
        val req = facebook.buildAuthRequest()
        pendingFacebookState = req.state
        pendingFacebookVerifier = req.codeVerifier

        val intent = Intent(Intent.ACTION_VIEW, req.authUri)
        facebookLauncher.launch(intent)
    }

    fun getPendingFacebookCodeVerifier(): String? = pendingFacebookVerifier
}